mapper.select:
SELECT da.ma_du_an, da.ten_du_an, da.ngay_bat_dau, da.ngay_ket_thuc_du_kien, da.ngay_ket_thuc_thuc_te, da.trang_thai, da.luong_trach_nhiem,
lda.ma_loai_du_an, lda.ten_loai_du_an, lda.so_nhan_vien_toi_da,
pb.ma_phong_ban, pb.ten_phong_ban FROM du_an da JOIN loai_du_an lda ON da.ma_loai_du_an = lda.ma_loai_du_an JOIN phong_ban pb ON da.ma_phong_quan_ly = pb.ma_phong_ban WHERE da.ma_du_an = #{maDuAn}

SELECT DISTINCT nv.*
FROM nhan_vien nv
JOIN tham_gia_du_an tgd
    ON nv.ma_nhan_vien = tgd.ma_nhan_vien
WHERE tgd.ma_du_an = #{maDuAn}
AND tgd.thang = #{thang}
AND tgd.nam = #{nam}
